function mmErr(m){$('.isi_warning_delete').text(m||'Mutation gagal diproses.');$('.error_data_delete').fadeIn()}function flt(){return{tgl_awal:$('#filter_tgl_awal').val(),tgl_akhir:$('#filter_tgl_akhir').val(),mutation_type:$('#filter_mutation_type').val(),approval_status:$('#filter_approval_status').val(),keyword:$('#filter_keyword').val()}}function setSel(s,v,t){var e=$(s);if(!v){e.val(null).trigger('change');return}if(!e.find('option[value="'+v+'"]').length)e.append(new Option(t||v,v,true,true));e.val(v).trigger('change')}function ajaxSel(s,a,p){$(s).select2({width:'100%',allowClear:true,placeholder:p,dropdownParent:$('#modal_mutation'),ajax:{url:'<?=base_admin();?>modul/employee_mutation/employee_mutation_action.php?act='+a,type:'POST',dataType:'json',delay:250,data:function(x){return{term:x.term||''}},processResults:function(d){return{results:d.results||[]}}}})}
$(function(){if($.fn.datepicker)$('.date-field').datepicker({format:'yyyy-mm-dd',autoclose:true});if($.fn.select2){$('#filter_mutation_type,#filter_approval_status,#mutation_type,#new_employee_group,#new_employee_subgroup,#approval_status,#new_payroll_area,#new_pay_grade,#new_work_location_type,#new_shift_code,#reason_code').select2({width:'100%',allowClear:true});ajaxSel('#employee_id','employee_search','Pilih Employee');ajaxSel('#new_department_code','department_search','Pilih Department');ajaxSel('#new_job_title_id','job_title_search','Pilih Job Title');ajaxSel('#new_company_structure_id','company_structure_search','Pilih Org Unit');ajaxSel('#new_manager_employee_id','employee_search','Pilih Manager');ajaxSel('#new_cost_center_code','cost_center_search','Pilih Cost Center');ajaxSel('#new_profit_center_code','profit_center_search','Pilih Profit Center')}
var dt=$('#dtb_employee_mutation').DataTable({bProcessing:true,bServerSide:true,pageLength:25,dom:"<'row'<'col-sm-12'B>>"+"<'row'<'col-sm-6'l><'col-sm-6'f>>"+"<'row'<'col-sm-12'tr>>"+"<'row'<'col-sm-5'i><'col-sm-7'p>>",buttons:[{extend:'collection',text:<?=hr_js('common_export_data', 'Export Data');?>,buttons:['copyHtml5','excelHtml5']}],columnDefs:[{targets:[0,1],orderable:false,searchable:false}],ajax:{url:'<?=base_admin();?>modul/employee_mutation/employee_mutation_data.php',type:'post',data:function(d){$.extend(d,flt())},dataSrc:function(j){var k=j.kpi||{};$('#kpi_total').text(k.total||0);$('#kpi_draft').text(k.draft||0);$('#kpi_submitted').text(k.submitted||0);$('#kpi_posted').text(k.posted||0);return j.data||[]},error:function(x){mmErr(x.responseText)}}});
$('#btn_open_mm').click(function(){$('#form_mutation')[0].reset();$('#mm_id').val('');$('#employee_id,#new_department_code,#new_job_title_id,#new_company_structure_id,#new_manager_employee_id,#new_cost_center_code,#new_profit_center_code').val(null).trigger('change');$('#modal_mutation').modal({backdrop:'static',keyboard:false})});$('#btn_filter_mm').click(function(){dt.draw()});$('#btn_reset_mm').click(function(){$('#filter_tgl_awal').val('<?=$df;?>');$('#filter_tgl_akhir').val('<?=$dt;?>');$('#filter_mutation_type,#filter_approval_status').val('').trigger('change');$('#filter_keyword').val('');dt.draw()});$('.hide_alert_notif').click(function(){$('.error_data_delete').hide()});
$('#employee_id').on('change',function(){var id=$(this).val();if(!id)return;$.post('<?=base_admin();?>modul/employee_mutation/employee_mutation_action.php?act=employee_snapshot',{employee_id:id},function(r){if(r.status!=='good')return;var h=r.data;setSel('#new_department_code',h.department_code,h.department_code+' - '+(h.nm_dept||''));setSel('#new_job_title_id',h.job_title_id,(h.job_title_code||'')+' - '+(h.job_title_name||''));setSel('#new_company_structure_id',h.company_structure_id,(h.structure_code||'')+' - '+(h.structure_name||''));setSel('#new_manager_employee_id',h.manager_employee_id,'Manager ID '+h.manager_employee_id);setSel('#new_cost_center_code',h.cost_center_code,h.cost_center_code+' - '+(h.cost_center_name||''));setSel('#new_profit_center_code',h.profit_center_code,h.profit_center_code+' - '+(h.profit_center_name||''));$('#new_employee_group').val(h.employee_group).trigger('change');$('#new_employee_subgroup').val(h.employee_subgroup).trigger('change');$('#new_payroll_area').val(h.payroll_area).trigger('change');$('#new_pay_grade').val(h.pay_grade).trigger('change');$('#new_work_location_type').val(h.work_location_type).trigger('change');$('#new_shift_code').val(h.shift_code).trigger('change')},'json')});
$('#form_mutation').submit(function(e){e.preventDefault();$.post('<?=base_admin();?>modul/employee_mutation/employee_mutation_action.php?act=save',$(this).serialize(),function(r){if(r.status==='good'){$('#modal_mutation').modal('hide');dt.draw(false);Swal.fire('Saved','Mutation tersimpan.','success')}else mmErr(r.error_message)},'json').fail(function(x){mmErr(x.responseText)})});
$(document).on('click','.btn-mm-detail',function(){$.post('<?=base_admin();?>modul/employee_mutation/employee_mutation_action.php?act=detail',{id:$(this).data('id')},function(h){$('#mm_detail_body').html(h);$('#modal_mm_detail').modal('show')})});$(document).on('click','.btn-mm-edit',function(){var id=$(this).data('id');$.post('<?=base_admin();?>modul/employee_mutation/employee_mutation_action.php?act=get',{id:id},function(r){if(r.status!=='good'){mmErr(r.error_message);return}$('#btn_open_mm').click();var h=r.data;$('#mm_id').val(h.id);Object.keys(h).forEach(function(k){if($('#'+k).length)$('#'+k).val(h[k]).trigger('change')});setSel('#employee_id',h.employee_id,'Employee ID '+h.employee_id);setSel('#new_department_code',h.new_department_code,h.new_department_code);setSel('#new_job_title_id',h.new_job_title_id,'Job ID '+h.new_job_title_id);setSel('#new_company_structure_id',h.new_company_structure_id,'Org ID '+h.new_company_structure_id);setSel('#new_manager_employee_id',h.new_manager_employee_id,'Manager ID '+h.new_manager_employee_id);setSel('#new_cost_center_code',h.new_cost_center_code,h.new_cost_center_code);setSel('#new_profit_center_code',h.new_profit_center_code,h.new_profit_center_code)},'json')});$(document).on('click','.btn-mm-post',function(){var id=$(this).data('id'),no=$(this).data('no');Swal.fire({title:'Posting mutation?',text:no,showCancelButton:true}).then(function(x){if(!x.isConfirmed)return;$.post('<?=base_admin();?>modul/employee_mutation/employee_mutation_action.php?act=post',{id:id},function(r){if(r.status==='good'){dt.draw(false);Swal.fire('Posted',r.message,'success')}else mmErr(r.error_message)},'json')})});$(document).on('click','.btn-mm-delete',function(){var id=$(this).data('id');$.post('<?=base_admin();?>modul/employee_mutation/employee_mutation_action.php?act=delete',{id:id},function(r){if(r.status==='good')dt.draw(false);else mmErr(r.error_message)},'json')})});
</script>
